import gc
from scipy.sparse import csr_matrix
from scipy.sparse.csgraph import connected_components

# ============================================================
# PLUME DETECTION — enhancement-based, local-background aware
# ============================================================
# Patched version (v3):
#   * Background estimator: lower-half trimmed mean (P20-P50) instead of
#     median — median in a dense-source basin is itself polluted by
#     neighbouring plumes, biasing enhancements LOW.
#   * Clustering: adjacency-graph connected-components replacing grid-snap
#     CC. Grid-snap CC failed on orbit-edge days where TROPOMI pixel spacing
#     exceeds 5.6 km, leaving >50% of enhanced pixels as noise. Adjacency-
#     graph CC builds a BallTree on actual pixel positions and connects pixels
#     within 1.1 × TROPOMI_PIXEL_KM (6.16 km), which admits physically
#     adjacent pixels and rejects diagonal neighbours (√2 × 5.6 = 7.9 km)
#     without requiring a regular grid.
#   * Cross-wind pixel flag (is_crosswind_outlier) for downstream IME
#     integration — excludes pixels beyond 1.5 TROPOMI pixels from the
#     along-wind axis (neighbour-source bleed).
# ============================================================

# --------------------------------
# 1. Clean + prepare
# --------------------------------
pdf = pdf.replace([np.inf, -np.inf], np.nan)
pdf = pdf.dropna(subset=["latitude", "longitude", "ch4", "datetime"])

QA_MIN       = 0.5
CH4_MIN_PPB  = 1_700
CH4_MAX_PPB  = 3_000

qa_ok  = pdf["qa_value"].isna() | (pdf["qa_value"] >= QA_MIN)
ch4_ok = pdf["ch4"].between(CH4_MIN_PPB, CH4_MAX_PPB)

before_qa = len(pdf)
pdf = pdf[qa_ok & ch4_ok].copy()
print(f"QA/CH4 filter removed {before_qa - len(pdf):,} of {before_qa:,} pixels")

pdf["date"] = pd.to_datetime(pdf["datetime"]).dt.date
print(f"Pixels after QA: {len(pdf):,}")

# --------------------------------
# 2. Physical parameters
# --------------------------------
TROPOMI_PIXEL_KM          = 5.6

# Clustering — adjacency-graph CC on actual pixel positions.
# CONNECT_KM = 1.1 × pixel admits direct neighbours (≤5.6 km apart) and
# rejects diagonal neighbours (√2 × 5.6 = 7.9 km apart). MIN_SAMPLES is
# the minimum component size; smaller components are labelled -1 (noise).
CONNECT_KM                = TROPOMI_PIXEL_KM * 1.1   # 6.16 km
MIN_SAMPLES               = 3

# Local background computation
BG_ANNULUS_INNER_KM       = 15.0
BG_ANNULUS_OUTER_KM       = 40.0
BG_MIN_PIXELS             = 40

# Trimmed-mean window for background (Varon 2018 §2.2 "clean-air baseline")
BG_TRIM_LO_PCT            = 20.0  # exclude bottom 20% — retrieval-noise tail
BG_TRIM_HI_PCT            = 50.0  # exclude top 50% — plume-contaminated tail

# Enhancement thresholds
# PIXEL_ENH_THRESHOLD_PPB raised 10 → 12 to compensate for the trimmed-mean
# background running ~2 ppb lower than the old median estimator.
PIXEL_ENH_THRESHOLD_PPB   = 12.0
MIN_CLUSTER_MEAN_ENH_PPB  = 14.0  # raised from 12 — pixel threshold at 12
                                  # made 12 ppb mean a no-op filter.
MIN_CLUSTER_CV            = 0.05

# Cluster geometry constraints
MAX_EXTENT_KM             = 35.0
MIN_EXTENT_KM             = TROPOMI_PIXEL_KM * 0.5
MIN_CLUSTER_PEAK_ENH_PPB  = 18.0

# Cross-wind masking (flag only — emissions notebook enforces)
# 1.5 TROPOMI pixels = 8.4 km. Varon 2018 Fig.4: cross-wind plume signal
# decays to background within ~1.5 pixels of the transport axis.
CROSSWIND_HALF_WIDTH_KM   = 1.5 * TROPOMI_PIXEL_KM   # 8.4 km

# --------------------------------
# 3. Helpers
# --------------------------------
def compute_local_enhancement(day_df):
    """
    Per-pixel enhancement = CH4 - trimmed_mean(CH4 in 15–40 km annulus).

    Trimmed mean over P20–P50 of the annulus is used instead of the median
    because (a) in a dense-source basin the median is contaminated by
    adjacent weak plumes, and (b) the bottom 20% is dominated by cloud-edge
    and retrieval-noise outliers. P20–P50 is the "clean-air baseline".
    """
    coords_rad = np.radians(day_df[["latitude", "longitude"]].to_numpy())
    ch4_arr    = day_df["ch4"].to_numpy()

    tree      = BallTree(coords_rad, metric="haversine")
    r_outer   = BG_ANNULUS_OUTER_KM / 6371.0
    r_inner   = BG_ANNULUS_INNER_KM / 6371.0

    idx_outer = tree.query_radius(coords_rad, r=r_outer)
    idx_inner = tree.query_radius(coords_rad, r=r_inner)

    enhancements = np.full(len(day_df), np.nan)
    for i in range(len(day_df)):
        annulus = np.setdiff1d(idx_outer[i], idx_inner[i], assume_unique=False)
        if annulus.size >= BG_MIN_PIXELS:
            vals = ch4_arr[annulus]
            lo, hi = np.percentile(vals, [BG_TRIM_LO_PCT, BG_TRIM_HI_PCT])
            clean  = vals[(vals >= lo) & (vals <= hi)]
            if clean.size >= max(5, BG_MIN_PIXELS // 4):
                enhancements[i] = ch4_arr[i] - clean.mean()
    return enhancements


def cluster_extent_km(group):
    if len(group) < 2:
        return 0.0
    lat_mid = group["latitude"].mean()
    lat_km  = (group["latitude"].max()  - group["latitude"].min())  * 111.0
    lon_km  = (group["longitude"].max() - group["longitude"].min()) * 111.0 * np.cos(np.radians(lat_mid))
    return float(np.sqrt(lat_km**2 + lon_km**2))


def aspect_ratio(group):
    """PC1 span / PC2 span. Wind-advected plumes are elongated."""
    if len(group) < 2:
        return np.nan
    lat_mid = group["latitude"].mean()
    x = (group["longitude"].values - group["longitude"].mean()) * 111320 * np.cos(np.radians(lat_mid))
    y = (group["latitude"].values  - group["latitude"].mean())  * 111320
    pts = np.unique(np.column_stack([x, y]), axis=0)
    if pts.shape[0] < 2:
        return np.nan
    pca   = PCA(n_components=2).fit(pts)
    proj1 = pts @ pca.components_[0]
    proj2 = pts @ pca.components_[1]
    span1 = proj1.max() - proj1.min()
    span2 = proj2.max() - proj2.min()
    return float(span1 / span2) if span2 > 1.0 else np.nan


def adjacency_cc_labels(high_df):
    """
    Adjacency-graph connected components on actual TROPOMI pixel positions.
    Returns an array of integer labels (len = len(high_df)); noise = -1.

    Why not grid-snapping CC:
      TROPOMI L2 pixels are on an irregular orbital swath, not a regular
      lat/lon grid. At swath edges, pixel centres are 6–8 km apart in the
      across-track direction. Snapping to a 5.6 km grid misplaces these
      pixels into non-adjacent cells, breaking connectivity and leaving
      >50% of enhanced pixels as unclustered noise on affected days.

    This approach:
      1. Builds a BallTree on actual haversine pixel positions.
      2. Connects pixels within CONNECT_KM = 1.1 × TROPOMI_PIXEL_KM (6.16 km).
         - Direct neighbours are ≤5.6 km apart → admitted.
         - Diagonal neighbours are √2 × 5.6 = 7.9 km apart → rejected.
         This preserves no-diagonal-chaining without needing a regular grid.
      3. Runs scipy connected_components on the sparse adjacency graph.
      4. Labels components smaller than MIN_SAMPLES as noise (-1).
    """
    if len(high_df) == 0:
        return np.array([], dtype=int)

    n           = len(high_df)
    connect_rad = CONNECT_KM / 6371.0
    coords_rad  = np.radians(high_df[["latitude", "longitude"]].to_numpy())

    tree    = BallTree(coords_rad, metric="haversine")
    indices = tree.query_radius(coords_rad, r=connect_rad)

    rows, cols = [], []
    for i, neighbours in enumerate(indices):
        for j in neighbours:
            if i != j:
                rows.append(i)
                cols.append(j)

    if not rows:
        return np.full(n, -1, dtype=int)

    data  = np.ones(len(rows), dtype=np.int8)
    graph = csr_matrix((data, (rows, cols)), shape=(n, n))
    n_components, labels = connected_components(
        graph, directed=False, return_labels=True
    )

    # Drop components smaller than MIN_SAMPLES
    counts = np.bincount(labels, minlength=n_components)
    small  = np.where(counts < MIN_SAMPLES)[0]
    if small.size:
        labels = np.where(np.isin(labels, small), -1, labels)

    n_noise = (labels == -1).sum()
    if n > 0 and n_noise / n > 0.5:
        print(f"  WARNING: {n_noise}/{n} enhanced pixels unclustered. "
              f"Possible cause: very sparse coverage day (n={n} pixels). "
              f"Check whether this date has partial swath coverage.")
    return labels


# --------------------------------
# 4. Per-day enhancement + adjacency-CC clustering
# --------------------------------
results           = []
global_cluster_id = 0
per_day_stats     = []

for date, day_df in pdf.groupby("date"):
    day_df = day_df.reset_index(drop=True)

    if len(day_df) < BG_MIN_PIXELS:
        continue

    # Per-pixel enhancement vs local annular background (trimmed mean)
    day_df["ch4_enh"] = compute_local_enhancement(day_df)
    day_df            = day_df.dropna(subset=["ch4_enh"])

    # Keep only pixels enhanced above per-pixel noise floor
    high = day_df[day_df["ch4_enh"] >= PIXEL_ENH_THRESHOLD_PPB].copy()
    per_day_stats.append({"date": date, "n_pixels": len(day_df), "n_enhanced": len(high)})
    if len(high) < MIN_SAMPLES:
        continue

    # Adjacency-graph connected-components clustering
    labels = adjacency_cc_labels(high)
    high["cluster_local"] = labels

    # Remap local → global IDs
    local_to_global = {-1: -1}
    for lid in sorted(l for l in np.unique(labels) if l != -1):
        local_to_global[lid] = global_cluster_id
        global_cluster_id   += 1
    high["cluster"] = high["cluster_local"].map(local_to_global)
    results.append(high.drop(columns=["cluster_local"]))

if not results:
    raise RuntimeError("No clusters formed. Check QA filter and enhancement thresholds.")

all_high = pd.concat(results, ignore_index=True)
plumes   = all_high[all_high["cluster"] != -1].copy()
print(f"Initial clusters:            {plumes['cluster'].nunique()}")

# --------------------------------
# 5. Cluster-level physical QA filters
# --------------------------------
cluster_qa = plumes.groupby("cluster").agg(
    mean_enh = ("ch4_enh", "mean"),
    max_enh  = ("ch4_enh", "max"),
    std_enh  = ("ch4_enh", "std"),
    n_pixels = ("ch4_enh", "size"),
).reset_index()
cluster_qa["cv_enh"] = cluster_qa["std_enh"] / cluster_qa["mean_enh"].replace(0, np.nan)

extents_full = plumes.groupby("cluster").apply(cluster_extent_km, include_groups=False)
cluster_qa["extent_km"] = cluster_qa["cluster"].map(extents_full)

cluster_qa["pixel_density_per_km"] = (
    cluster_qa["n_pixels"]
    / cluster_qa["extent_km"].clip(lower=0.1)
)
MIN_PIXEL_DENSITY_PER_KM = 0.15

keep_mask = (
    (cluster_qa["mean_enh"]             >= MIN_CLUSTER_MEAN_ENH_PPB) &
    (cluster_qa["cv_enh"]               >= MIN_CLUSTER_CV)           &
    (cluster_qa["extent_km"]            >= MIN_EXTENT_KM)            &
    (cluster_qa["max_enh"]              >= MIN_CLUSTER_PEAK_ENH_PPB) &
    (cluster_qa["extent_km"]            <= MAX_EXTENT_KM)            &
    (cluster_qa["pixel_density_per_km"] >= MIN_PIXEL_DENSITY_PER_KM)
)
valid_ids = set(cluster_qa.loc[keep_mask, "cluster"])

print(f"Rejected by mean_enh < {MIN_CLUSTER_MEAN_ENH_PPB} ppb : "
      f"{(cluster_qa['mean_enh']  < MIN_CLUSTER_MEAN_ENH_PPB).sum()}")
print(f"Rejected by CV < {MIN_CLUSTER_CV} (uniform background) : "
      f"{(cluster_qa['cv_enh']    < MIN_CLUSTER_CV).sum()}")
print(f"Rejected by extent > {MAX_EXTENT_KM} km (multi-source) : "
      f"{(cluster_qa['extent_km'] > MAX_EXTENT_KM).sum()}")
print(f"Rejected by extent < {MIN_EXTENT_KM:.1f} km (single-pixel) : "
      f"{(cluster_qa['extent_km'] < MIN_EXTENT_KM).sum()}")
print(f"Rejected by density < {MIN_PIXEL_DENSITY_PER_KM} px/km : "
      f"{(cluster_qa['pixel_density_per_km'] < MIN_PIXEL_DENSITY_PER_KM).sum()}")

plumes = plumes[plumes["cluster"].isin(valid_ids)].copy()

# --------------------------------
# 6. Aspect-ratio flag (soft, not filter)
# --------------------------------
ratios = plumes.groupby("cluster").apply(aspect_ratio, include_groups=False)
plumes["is_elongated"] = plumes["cluster"].isin(set(ratios[ratios >= 1.5].index))

borderline_ids = set(cluster_qa.loc[
    (cluster_qa["extent_km"] > 28.0) & (cluster_qa["extent_km"] <= MAX_EXTENT_KM),
    "cluster"
])
plumes["is_multisource_candidate"] = plumes["cluster"].isin(borderline_ids)

# --------------------------------
# 6b. Cross-wind outlier flag
# --------------------------------
try:
    weather_raw = spark.table("dbo.weather").toPandas()
    weather_raw["date"] = pd.to_datetime(weather_raw["date"]).dt.date

    def _circular_mean_deg(angles):
        r = np.radians(angles.dropna())
        if len(r) == 0:
            return np.nan
        return float(np.degrees(np.arctan2(np.sin(r).mean(), np.cos(r).mean())) % 360)

    weather_day = (
        weather_raw
        .groupby("date")["wind_direction"]
        .apply(_circular_mean_deg)
        .reset_index()
        .rename(columns={"wind_direction": "wind_dir"})
    )

    plumes      = plumes.merge(weather_day, on="date", how="left")
    has_wind_dir = plumes["wind_dir"].notna().any()
    n_missing   = plumes["wind_dir"].isna().sum()
    if n_missing:
        print(f"  Cross-wind flag: {n_missing} plume pixels have no wind direction "
              f"(date not in weather table) — those pixels will not be flagged.")

except Exception as e:
    print(f"Could not join weather for cross-wind flag ({type(e).__name__}: {e}). "
          f"Falling back to no cross-wind filtering.")
    plumes["wind_dir"] = np.nan
    has_wind_dir       = False


def _flag_crosswind(group):
    if group["wind_dir"].isna().all():
        return pd.Series(False, index=group.index)
    wd     = float(group["wind_dir"].iloc[0])
    theta  = np.radians(270.0 - wd)        # meteorological FROM → mathematical TO
    ux, uy = np.cos(theta), np.sin(theta)
    lat_mid = group["latitude"].mean()
    x = (group["longitude"].values - group["longitude"].mean()) * 111_320 * np.cos(np.radians(lat_mid))
    y = (group["latitude"].values  - group["latitude"].mean())  * 111_320
    cw_m = np.abs(-x * uy + y * ux)        # perpendicular (cross-wind) component
    return pd.Series(cw_m > CROSSWIND_HALF_WIDTH_KM * 1_000.0, index=group.index)


if has_wind_dir:
    plumes["is_crosswind_outlier"] = (
        plumes.groupby("cluster", group_keys=False)
              .apply(_flag_crosswind, include_groups=False)
    )
else:
    plumes["is_crosswind_outlier"] = False

# -----------------------------------------------------------
# Pixel area: TROPOMI high-res mode (post-2019-08-06)
# -----------------------------------------------------------
# 5.5 km × 3.5 km = 1.925e7 m². The 3.85e7 value (7 km × 5.5 km) applies
# only to pre-Aug-2019 data. IMPORTANT: emissions notebook Cells 5 and 7
# must also use 1.925e7 — the 3.85e7 comments there refer to pre-2019 mode.
TROPOMI_PIXEL_AREA_M2 = 1.925e7
plumes["pixel_area_m2"] = TROPOMI_PIXEL_AREA_M2

del all_high
gc.collect()

# --------------------------------
# 7. Diagnostics
# --------------------------------
kept = plumes["cluster"].nunique()
print(f"\n=== Plume detection summary ===")
print(f"Valid plumes after all filters : {kept}")
print(f"  Elongated (aspect ≥ 1.5)     : {plumes.groupby('cluster')['is_elongated'].first().sum()}")
print(f"  Borderline multi-source      : {plumes.groupby('cluster')['is_multisource_candidate'].first().sum()}")
print(f"  Pixels with cross-wind flag  : {plumes['is_crosswind_outlier'].sum()} "
      f"({100*plumes['is_crosswind_outlier'].mean():.1f}%)")

if kept > 0:
    print(f"\nCluster size (pixels):")
    print(plumes.groupby("cluster").size().describe().round(1).to_string())
    kept_qa = cluster_qa[cluster_qa["cluster"].isin(valid_ids)]
    print(f"\nCluster extent (km):       median={kept_qa['extent_km'].median():.1f}  "
          f"p95={kept_qa['extent_km'].quantile(0.95):.1f}  "
          f"max={kept_qa['extent_km'].max():.1f}")
    print(f"Mean enhancement (ppb):    median={kept_qa['mean_enh'].median():.1f}  "
          f"p95={kept_qa['mean_enh'].quantile(0.95):.1f}")
    print(f"Intra-cluster CV:          median={kept_qa['cv_enh'].median():.3f}  "
          f"min={kept_qa['cv_enh'].min():.3f}")
    print(f"\nPer-day cluster count:")
    print(plumes.groupby("date")["cluster"].nunique().describe().round(1).to_string())

