# ================================
# VISUALIZATION — HEATMAP (3-panel)
# ================================
# Panel 1: all QA-passing pixels, log-density hexbin (background field)
# Panel 2: plume-cluster pixels only, mean ch4_enh as hexbin heatmap
# Panel 3: same as panel 2 with cross-wind outliers overplotted in contrast
# ================================

from scipy.stats import gaussian_kde
from matplotlib.colors import LogNorm, Normalize

world = gpd.read_file(
    "https://naturalearth.s3.amazonaws.com/110m_cultural/ne_110m_admin_0_countries.zip"
)

gdf_all = gpd.GeoDataFrame(
    pdf,
    geometry=gpd.points_from_xy(pdf["longitude"], pdf["latitude"]),
    crs="EPSG:4326",
)
gdf_plumes = gpd.GeoDataFrame(
    plumes,
    geometry=gpd.points_from_xy(plumes["longitude"], plumes["latitude"]),
    crs="EPSG:4326",
)
gdf_core = gdf_plumes[~gdf_plumes["is_crosswind_outlier"]].copy()
gdf_cw   = gdf_plumes[ gdf_plumes["is_crosswind_outlier"]].copy()

XLIM = (-105, -90)
YLIM = (  25,  35)

fig, axes = plt.subplots(1, 3, figsize=(21, 6), constrained_layout=True)

# ------------------------------------------------------------------
# Shared helper: draw basemap on an axis
# ------------------------------------------------------------------
def _basemap(ax, title):
    world.boundary.plot(ax=ax, linewidth=0.4, color="#333333", zorder=5)
    ax.set_xlim(*XLIM)
    ax.set_ylim(*YLIM)
    ax.set_title(title, fontsize=11, pad=6)
    ax.set_xlabel("Longitude", fontsize=9)
    ax.set_ylabel("Latitude",  fontsize=9)
    ax.tick_params(labelsize=8)

# ------------------------------------------------------------------
# Panel 1 — all QA pixels, log-count hexbin
# ------------------------------------------------------------------
ax1 = axes[0]
hb1 = ax1.hexbin(
    gdf_all["longitude"], gdf_all["latitude"],
    gridsize=100, cmap="YlOrRd", mincnt=1,
    norm=LogNorm(), zorder=1, alpha=0.9,
    reduce_C_function=np.size,          # count pixels per hex
)
cb1 = fig.colorbar(hb1, ax=ax1, pad=0.02, shrink=0.85)
cb1.set_label("Pixel count (log)", fontsize=8)
_basemap(ax1, "All QA pixels — CH₄ observation density")

# ------------------------------------------------------------------
# Panel 2 — plume pixels only, mean enhancement as hexbin heatmap
# ------------------------------------------------------------------
ax2 = axes[1]
if len(gdf_plumes) > 0:
    hb2 = ax2.hexbin(
        gdf_plumes["longitude"], gdf_plumes["latitude"],
        C=gdf_plumes["ch4_enh"],
        gridsize=80, cmap="plasma", mincnt=1,
        reduce_C_function=np.mean,      # mean enhancement per hex cell
        zorder=1, alpha=0.9,
    )
    cb2 = fig.colorbar(hb2, ax=ax2, pad=0.02, shrink=0.85)
    cb2.set_label("Mean CH₄ enhancement (ppb)", fontsize=8)
_basemap(ax2, f"Plume pixels — mean enhancement  (n={len(gdf_plumes):,} px, "
              f"{gdf_plumes['cluster'].nunique():,} clusters)")

# ------------------------------------------------------------------
# Panel 3 — plume core heatmap + cross-wind outliers as contour overlay
# ------------------------------------------------------------------
ax3 = axes[2]

# Core pixels as enhancement heatmap (same as panel 2)
if len(gdf_core) > 0:
    hb3 = ax3.hexbin(
        gdf_core["longitude"], gdf_core["latitude"],
        C=gdf_core["ch4_enh"],
        gridsize=80, cmap="plasma", mincnt=1,
        reduce_C_function=np.mean,
        zorder=1, alpha=0.9,
    )
    cb3 = fig.colorbar(hb3, ax=ax3, pad=0.02, shrink=0.85)
    cb3.set_label("Mean CH₄ enhancement — core pixels (ppb)", fontsize=8)

# Cross-wind outliers: KDE contour so density is visible without
# individual point scatter.  Only drawn when enough points exist for KDE.
if len(gdf_cw) >= 10:
    lon_cw = gdf_cw["longitude"].values
    lat_cw = gdf_cw["latitude"].values

    # Evaluate KDE on a grid covering the AOI
    lon_grid = np.linspace(*XLIM, 200)
    lat_grid = np.linspace(*YLIM, 120)
    LON, LAT = np.meshgrid(lon_grid, lat_grid)
    kde       = gaussian_kde(np.vstack([lon_cw, lat_cw]), bw_method=0.15)
    Z         = kde(np.vstack([LON.ravel(), LAT.ravel()])).reshape(LON.shape)

    # Filled contour at the 60th / 80th / 95th percentile of KDE density
    levels = np.percentile(Z[Z > 0], [60, 80, 95])
    if len(np.unique(levels)) == len(levels):       # guard against flat Z
        ax3.contourf(LON, LAT, Z, levels=levels,
                     cmap="cool", alpha=0.45, zorder=3)
        ax3.contour( LON, LAT, Z, levels=levels,
                     colors="cyan", linewidths=0.6, alpha=0.7, zorder=4)

    # Lightweight scatter on top just to show individual positions
    ax3.scatter(
        lon_cw, lat_cw,
        c="cyan", s=6, edgecolors="none", alpha=0.4, zorder=5,
        label=f"Cross-wind outliers (n={len(gdf_cw):,})",
    )
    ax3.legend(loc="lower left", fontsize=7, framealpha=0.7)
elif len(gdf_cw) > 0:
    # Too few for KDE — fall back to plain scatter
    ax3.scatter(
        gdf_cw["longitude"], gdf_cw["latitude"],
        c="cyan", s=8, edgecolors="none", alpha=0.6, zorder=5,
        label=f"Cross-wind outliers (n={len(gdf_cw):,})",
    )
    ax3.legend(loc="lower left", fontsize=7, framealpha=0.7)

_basemap(ax3, f"Core plume enhancement + cross-wind outliers  "
              f"({100*len(gdf_cw)/max(len(gdf_plumes),1):.1f}% of plume px)")

fig.suptitle(
    "Permian Basin — TROPOMI methane plume detection  "
    f"({plumes['date'].nunique()} dates, {gdf_plumes['cluster'].nunique():,} clusters)",
    fontsize=13, y=1.01,
)
plt.savefig("permian_plume_heatmap.png", dpi=150, bbox_inches="tight")
plt.show()
print("Saved: permian_plume_heatmap.png")

