# ================================
# SAVING PLUME DATA TO TABLE
# ================================
TABLE_NAME = "dbo.methane_plumes_dbscan"

# --------------------------------
# 1. Clean + type-normalise
# --------------------------------
plumes = plumes.replace([np.inf, -np.inf], None)

for col_name in ["latitude", "longitude", "ch4", "ch4_enh", "qa_value", "wind_dir"]:
    if col_name in plumes.columns:
        plumes[col_name] = pd.to_numeric(plumes[col_name], errors="coerce")

plumes["datetime"] = pd.to_datetime(plumes["datetime"], errors="coerce")
plumes["cluster"]  = pd.to_numeric(plumes["cluster"], errors="coerce")

# Drop nulls BEFORE type conversions that can't handle NaN
plumes = plumes.dropna(subset=["latitude", "longitude", "datetime", "cluster"])

# Now safe to cast — no NaNs remain
plumes["cluster"] = plumes["cluster"].astype(int)

# Convert Timestamp → Python datetime AFTER dropna (preserves Series dtype)
plumes["datetime"] = plumes["datetime"].apply(lambda x: x.to_pydatetime())

# Ensure new cross-wind column exists even on the fallback path where it
# was never populated (Spark rejects frames that don't match the schema).
if "is_crosswind_outlier" not in plumes.columns:
    plumes["is_crosswind_outlier"] = False
plumes["is_crosswind_outlier"] = plumes["is_crosswind_outlier"].fillna(False).astype(bool)

if "wind_dir" not in plumes.columns:
    plumes["wind_dir"] = np.nan

# --------------------------------
# 2. Output schema — include ch4_enh for downstream IME
# --------------------------------
keep_cols = [
    "latitude", "longitude", "ch4", "ch4_enh", "qa_value",
    "datetime", "gas", "instrument", "platform", "cluster",
    "pixel_area_m2",
    "is_elongated", "is_multisource_candidate",
    "is_crosswind_outlier", "wind_dir",
]

plumes = plumes[keep_cols]

schema = StructType([
    StructField("latitude",                 DoubleType(),    True),
    StructField("longitude",                DoubleType(),    True),
    StructField("ch4",                      DoubleType(),    True),
    StructField("ch4_enh",                  DoubleType(),    True),
    StructField("qa_value",                 DoubleType(),    True),
    StructField("datetime",                 TimestampType(), True),
    StructField("gas",                      StringType(),    True),
    StructField("instrument",               StringType(),    True),
    StructField("platform",                 StringType(),    True),
    StructField("cluster",                  IntegerType(),   True),
    StructField("pixel_area_m2",            DoubleType(),    True),
    StructField("is_elongated",             BooleanType(),   True),
    StructField("is_multisource_candidate", BooleanType(),   True),
    StructField("is_crosswind_outlier",     BooleanType(),   True),
    StructField("wind_dir",                 DoubleType(),    True),
])

# --------------------------------
# 3. Convert to Spark + report (not silent) deduplication
# --------------------------------
print(f"Rows before Spark: {len(plumes)}")   # sanity check
spark_df = spark.createDataFrame(plumes, schema=schema)
before   = spark_df.count()
spark_df = spark_df.dropDuplicates(["latitude", "longitude", "datetime"])
after    = spark_df.count()
if before != after:
    print(f"Deduplicated {before - after} pixel(s) with identical (lat, lon, datetime)")

spark_df = spark_df.coalesce(2)

# --------------------------------
# 4. Overwrite (cluster IDs change every run)
# --------------------------------
(spark_df.write
    .mode("overwrite")
    .option("overwriteSchema", "true")
    .format("delta")
    .saveAsTable(TABLE_NAME))

print(f"Plume data written to {TABLE_NAME} ({after:,} rows, {plumes['cluster'].nunique()} clusters)")

